using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the training service as a singleton so metrics persist
builder.Services.AddSingleton<ModelTrainingService>();

// Build the app so we can train the model before configuring the prediction pool
var app = builder.Build();

// Train model at startup
var trainingService = app.Services.GetRequiredService<ModelTrainingService>();
trainingService.TrainAndSave();

// Register the PredictionEnginePool with the trained model
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainingService.GetModelPath());

// Rebuild with prediction pool registered
var fullBuilder = WebApplication.CreateBuilder(args);
fullBuilder.Services.AddControllers();
fullBuilder.Services.AddSingleton(trainingService);
fullBuilder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainingService.GetModelPath());

var fullApp = fullBuilder.Build();
fullApp.MapControllers();
fullApp.Run();

